import React, { useState, useEffect } from "react";

import { Autoplay } from "swiper";
import { Swiper, SwiperSlide } from "swiper/react";
import axios from "axios";
// Import Swiper styles
import "swiper/css";
import "swiper/css/navigation";
import "swiper/css/scrollbar";
import "swiper/css/autoplay";
import "swiper/css/effect-coverflow";
import "swiper/swiper-bundle.min.css";
import "swiper/swiper.min.css";

const OurClients = () => {
	const [clients, setClients] = useState([]);
	if (clients.length === 0) {
		axios
			.get("https://" + process.env.REACT_APP_SERVER + "/api/clientList/")
			.then((data) => setClients(data["data"]["data"]))
			.catch((error) => console.log(error));
	}
	return (
		<div className="my-10">
			<div className="box h-[5rem] w-[25rem] relative flex justify-start items-start ml-[2rem] group">
				<div className="h-12 w-1.5 bg-[#004B95] absolute mr-[1rem] origin-left group-hover:w-[15rem] duration-300 group"></div>
				<h4 className="text-[24px] absolute font-bold text-[#004B95] mt-[0.5rem] ml-[1rem] group-hover:text-white group-hover:translate-x-5 duration-300">Our clients</h4>
			</div>

			{/* <div className="logo flex flex-col space-y-10 mt-[3rem] items-center lg:flex-row lg:space-x-10 lg:justify-center"> */}
			<div className="logo flex flex-row flex-nowrap overflow-x-auto gap-10 items-center my-5 no-scrollbar h-32">
				<Swiper
					grabCursor={true}
					centeredSlides={true}
					slidesPerView={(window.innerWidth > 640) ? 8 : 2}
					autoplay={() => {
						if (clients.length > 8) {
							return {
								delay: 2500,
								disableOnInteraction: false,
							};
						} else {
							return {
								delay: 250000,
								disableOnInteraction: false,
							};
						}
					}}
					initialSlide={() => {
						if (clients.length > 8) {
							return 1;
						} else {
							return 2;
						}
					}}
					modules={[Autoplay]}
					className="mySwiper flex justify-center w-full"
				>
					{clients.map((item, index) => (
						<SwiperSlide key={index} className="flex ">
							<div className="group w-32 mx-auto flex items-center">
								<img
									onError={({ currentTarget }) => {
										currentTarget.onerror = null; // prevents looping
										currentTarget.src = "/static/images/logoOnly.png";
									}}
									src={"https://" + process.env.REACT_APP_SERVER + item[1]}
									className="grayscale group-hover:grayscale-0 duration-700 w-full h-full object-contain"
								/>
							</div>
						</SwiperSlide>
					))}
				</Swiper>
			</div>
		</div>
	);
};

export default OurClients;
