import React from "react";
const BlogsList = ({ listdData }) => {
	return (
		<div className="w-full max-h-[calc(100vh-7rem)] h-fit transition-all duration-300 border-[#004B95] border-[1px] rounded-[10px] bg-white overflow-hidden sticky top-24">
			<div className="box h-[5rem] w-fit pl-6 relative flex justify-start items-start group mt-5">
				<div className="h-12 w-1.5 bg-[#004B95] absolute mr-[1rem] origin-left group-hover:w-full duration-300 group"></div>
				<h4 className="text-[24px] font-bold text-[#004B95] mt-[0.5rem] ml-[0.7rem] group-hover:text-white group-hover:translate-x-5 duration-300 capitalize">Categories</h4>
			</div>

			<div className=" flex justify-between px-[20px] items-center relative border-[1px] border-[#004B95] rounded-[5px] h-[38px]  mx-[10%] w-[80%]">
				<input
					type="text"
					name="catSearch"
					id="catSearch"
					onKeyUp={() => {
						let categories = document.querySelectorAll(".category");
						let value = document.getElementById("catSearch").value;
						categories.forEach((item) => {
							if (item.getAttribute("data-category").toLowerCase().includes(value.toLowerCase())) {
								item.style.display = "flex";
							} else {
								item.style.display = "none";
							}
						});
					}}
					placeholder="Search here"
					className=" font-medium  leading-[30px]  outline-none focus:outline-none  tracking-[5%] text-[#004B95] w-[80%]"
				/>
				<i className="fa-solid fa-magnifying-glass text-[#004B95] relative"></i>
			</div>
			<div className="w-full max-h-[calc(100vh-7rem-190px)] h-fit transition-all duration-300 mb-5 px-[20px] mt-[20px] overflow-y-scroll overflow-x-hidden">
				<ul>
					{listdData.map((item, index) => {
						return (
							<a href={`/${item[1]}`} key={index} data-category={item[0]} className="category">
								<div className="flex flex-row flex-nowrap items-center gap-3">
									<li title={item[0]} className="font-poppins font-medium text-[1rem] h-10 leading-[30px] text-[#004B95] list-disc pb-[18px] pt-[12px] discriptionTruncate-1 hover:font-bold hover:scale-110 origin-left transition-all duration-300 ">
										&#x2022;&nbsp;{item[0]}
									</li>
								</div>
								<div className="bg-[#004a9533] h-0.5 mt-3 rounded-full"></div>
							</a>
						);
					})}
				</ul>
			</div>
		</div>
	);
};

export default BlogsList;
