import React, { useState } from "react";

const RevieStars = (props) => {
	let data = [];
	for (let i = 0; i < props.stars; i++) {
		data.push({ stars: "/static/images/Star 1.png" });
	}
	for (let i = 0; i < 5 - props.stars; i++) {
		data.push({ laststars: "/static/images/Star 5.png" });
	}
	return (
		<>
			<div className="flex flex-row gap-1">
				{data.map((data, index) => {
					return (
						<div key={index}>
							<div className=" mt-[0.5rem]">
								<img src={data.stars} />
								<img src={data.laststars} />
							</div>
						</div>
					);
				})}
			</div>
		</>
	);
};

export default RevieStars;
