import React, { useState } from "react";
import Background2 from "../assets/images/background2.jpg";
import simage1 from "../assets/images/simage1.jpg";
import simage2 from "../assets/images/simage2.jpg";
import simage3 from "../assets/images/simage3.jpg";
import simage4 from "../assets/images/simage4.jpg";
import RevieStars from "./RevieStars";
import axios from "axios";
//import data from '../Datajson/data.json'

import { Navigation, Scrollbar, A11y } from "swiper";
import SwiperCore, { Autoplay, EffectCoverflow, Pagination } from "swiper";

import { Swiper, SwiperSlide } from "swiper/react";

// Import Swiper styles
import "swiper/css";
import "swiper/css/navigation";
import "swiper/css/pagination";
import "swiper/css/scrollbar";
//

import "swiper/swiper-bundle.min.css";
import "swiper/swiper.min.css";
import Quotation from "./Quotation";

SwiperCore.use([EffectCoverflow, Autoplay, Pagination]);

export const WhatPeopeSay = () => {
	const [review, setReview] = useState([]);
	if (review.length === 0) {
		axios
			.get("https://" + process.env.REACT_APP_SERVER + "/api/reviewFetcher/")
			.then((data) => setReview(data["data"]["data"]))
			.catch((error) => console.log(error));
	}
	return (
		<>
			<div className="box h-[5rem] w-[25rem] relative flex justify-start items-start ml-[2rem] group">
				<div className="h-12 w-1.5 bg-[#004B95] absolute mr-[1rem] origin-left group-hover:w-[20rem] duration-300 group"></div>
				<h4 className="text-[24px] absolute font-bold text-[#004B95] ml-[1rem] mt-[0.5rem] group-hover:text-white group-hover:translate-x-5 duration-300">What People Say</h4>
			</div>

			<div style={{ backgroundImage: "url(" + Background2 + ")", backgroundSize: "auto", width: "100%" }}>
				<Swiper
					// install Swiper modules
					modules={[Navigation, Pagination, Scrollbar, A11y, Autoplay]}
					spaceBetween={30}
					slidesPerView={(window.innerWidth > 640) ? 2 : 1}
					navigation={(window.innerWidth > 640) ? true : false}
					autoplay={{
						delay: 2500,
						disableOnInteraction: false,
					}}
				>
					{review.map((item, index) => (
						<SwiperSlide key={index}>
							<div className=" mt-5 mb-5 lg:px-14 px-2">
								<div className="max-w-md mx-auto min-h-[200px] max-h-[200px] py-4 w-full sm:w-[14rem] bg-[#D9D9D91A] border-2 border-[#787575] backdrop-blur-sm rounded-xl shadow-md overflow-hidden md:max-w-2xl lg:w-[100%] xl:w-[100%] md:w-[80%] 2xl:w-[100%]">
									<div className="flex flex-col sm:flex-row items-center justify-between">
										<div className="md:shrink-0 hidden sm:block">
											<img className="w-[4rem] ml-11 object-cover xl:w-[8rem] md:w-[6rem] rounded-lg" src={item.image} alt="Modern building architecture" />
										</div>
										<div className="p-5">
											<Quotation />
											<div className="ml-[3rem]">
											<p className="mr-[2rem] text-1 text-white discriptionTruncate xl:text-[0.9rem] md:text-[0.6rem]">{item.review}</p>
											<RevieStars stars={item.rating} />
											<div className="flex space-x-0.5 pt-[0.5rem] xl:pt-[1rem] sm:pt-[0.5rem]  ">
												<h3 className="text-white mr-[2rem] text-[0.8rem] xl:text-[0.8rem] sm:text-[0.7rem]">{item.name}</h3>
												<h3 className="text-white mr-[2rem] text-[0.8rem] xl:text-[0.8rem] sm:text-[0.7rem]">{item.time}</h3>
											</div>
											</div>
										</div>
									</div>
								</div>
							</div>
						</SwiperSlide>
					))}
				</Swiper>
			</div>
		</>
	);
};

export default WhatPeopeSay;
