import React, { useState } from "react";
import DisplayedProduct from "./DisplayedProduct";
import data from "./data.json";
import { Swiper, SwiperSlide } from "swiper/react";
import { Autoplay } from "swiper";
import "swiper/css";
import "swiper/css/scrollbar";
import "aos/dist/aos.css";
import CategoryCard from "../CategoryCard/CategoryCard";
import axios from "axios";

const MainProducts = () => {
	const [productShown, setProductShown] = useState(-1);
	const [category, setCategory] = useState([]);
	//homeCategoryList
	if (category.length === 0) {
		axios
			.get("https://" + process.env.REACT_APP_SERVER + "/api/homeCategoryList/")
			.then((data) => setCategory(data["data"]["data"]))
			.catch((error) => console.log(error));
	}
	return (
		<>
			<div className="box h-[5rem] w-[25rem] relative flex justify-start items-start ml-[2rem] group mt-6" id="ourProducts">
				<div className="h-12 w-1.5 bg-[#004B95] absolute mr-[1rem] origin-left group-hover:w-[16rem] duration-300 group"></div>
				<h4 className="text-[24px] absolute font-bold text-[#004B95] mt-[0.5rem] ml-[1rem] group-hover:text-white group-hover:translate-x-5 duration-300">Our Products</h4>
			</div>
			<div className="flex p-[10px] gap-[15px] max-w-full">
				{/* main products display */}
				<DisplayedProduct productShown={productShown} data={category[productShown]}/>
				<Swiper
					className=""
					slidesPerView={(window.innerWidth > 640) ? 4 : 2}
					spaceBetween={20}
					autoplay={{
						delay: 3000,
						disableOnInteraction: true,
					}}
					loop={true}
					modules={[Autoplay]}
				>
					{/* {returProductCards(data)} */}
					{category.map((item, index) => {
						if (index % 2 == 0) {
							let img = "";
							try {
								img = "https://" + process.env.REACT_APP_SERVER + item.products[0][1];
							} catch {
								img = "";
							}
							let img1 = "";
							try {
								img1 = "https://" + process.env.REACT_APP_SERVER + category[index + 1].products[0][1];
							} catch {
								img1 = "";
							}
							let component1 = <div></div>;
							try {
								component1 = <CategoryCard index={index} link={item.categoryLink} title={item.categoryName} description={item.discription} img={img} rating={10} stars={4} setProductShown={setProductShown} />;
							} catch {}
							let component2 = <div></div>;
							try {
								component2 = <CategoryCard index={index + 1} link={category[index + 1].categoryLink} title={category[index + 1].categoryName} description={category[index + 1].discription} img={img1} rating={10} stars={4} setProductShown={setProductShown} />;
							} catch {}
							return (
								<SwiperSlide className="h-32" key={index}>
									{component1}
									{component2}
								</SwiperSlide>
							);
						}
					})}
				</Swiper>
			</div>
		</>
	);
};

export default MainProducts;
