import React, { useState,useEffect } from "react";
import MainProducts from "./MainProductsNew";
// import BlogItemsDisplay from "./BlogItemsDisplay";
import BlogsList from "../Blogs/BlogsList";
import { useParams } from "react-router-dom";
import { ImQuotesLeft } from "react-icons/im";
import { ImQuotesRight } from "react-icons/im";
import axios from "axios";

import { Autoplay } from "swiper";

import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import "swiper/css/autoplay";
import "swiper/swiper-bundle.min.css";
import "swiper/swiper.min.css";

const BlogNew = () => {
	
	const[selectedOption,setSelectedOption]=useState(' ');
	const[showDropdown,setShowDropdown]=useState(false);
	const handleOptionSelect = (event) => {
		setSelectedOption(event.target.value);
	  };
	  useEffect(() => {
		const handleResize = () => {
		  setShowDropdown(window.innerWidth < 640); 
		};
	
		handleResize(); 
		window.addEventListener('resize', handleResize); 
	
		return () => {
		  window.removeEventListener('resize', handleResize); 
		};
	  }, []);

	const params = useParams();
	let temp = "Hot Products";
	if (params["link"] !== undefined) {
		temp = params["link"];
	}
	const [selectedCat, setSelectedCat] = useState(temp);
	if (selectedCat === undefined) {
		document.title = "Kijeka | Hot Products";
	} else {
		document.title = "Kijeka | " + selectedCat.replace(/-/g, " ").toUpperCase();
	}
	const [category, setCategory] = useState([]);
	const [products, setProducts] = useState([]);
	const [qoutes, setQoutes] = useState([]);
	if (qoutes.length === 0) {
		axios
			.get("https://" + process.env.REACT_APP_SERVER + "/api/quoteList/?category=" + selectedCat)
			.then((data) => setQoutes(data["data"]["data"]))
			.catch((error) => console.log(error));
	}
	if (category.length === 0) {
		axios
			.get("https://" + process.env.REACT_APP_SERVER + "/api/categorySideBar/")
			.then((data) => setCategory(data["data"]["data"]))
			.catch((error) => console.log(error));
	}
	if (products.length === 0) {
		// post in axios
		axios
			.get("https://" + process.env.REACT_APP_SERVER + "/api/getCategoryProducts/?category=" + selectedCat)
			.then((data) => setProducts(data["data"]["data"]))
			.catch((error) => console.log(error));
	}
	return (
		<div className="mt-16">
			<div className="w-full relative" style={{ backgroundImage: "url(/static/images/Qoutes1.png)", backgroundSize: "cover", backgroundRepeat: "no-repeat" }}>
				<div className="text-white">
					<Swiper
						grabCursor={true}
						centeredSlides={true}
						slidesPerView={1}
						autoplay={{
							delay: 3000,
							disableOnInteraction: false,
						}}
						loop={true}
						modules={[Autoplay]}
						className="mySwiper h-fit w-full  flex justify-between items-center"
					>
						{qoutes.map((item, index) => (
							<SwiperSlide className="w-full p-12" key={index}>
								<p className="flex  items-center justify-center text-3xl mt-2 text-center ml-5 relative">
									<ImQuotesLeft className=" w-10 h-10 -translate-y-5" />
									&nbsp;{item}
									<ImQuotesRight className=" w-10 h-10 -translate-y-5" />
								</p>
							</SwiperSlide>
						))}
					</Swiper>
				</div>
			</div>
			<div className="box h-[5rem] w-fit pl-10 relative flex justify-start items-start ml-[2rem] group mt-5">
				<div className="h-12 w-1.5 bg-[#004B95] absolute mr-[1rem] origin-left group-hover:w-full duration-300 group"></div>
				<h4 className="text-[24px] font-bold text-[#004B95] mt-[0.5rem] ml-[1rem] group-hover:text-white group-hover:translate-x-5 duration-300 capitalize">{selectedCat !== "" ? selectedCat.replace(/-/g, " ") : "Hot Products"}</h4>
			</div>

			<div className="sm:flex sm:flex-row sm:gap-5 sm:mb-5 sm:mx-5 flex flex-col ">
				<div className="sm:w-[30%] w-full sm:ml-[1%] mx-auto px-6">
				{window.innerWidth < 640 &&<div>
				<select value={selectedOption} onChange={handleOptionSelect}>
					<option value="">category </option>
					<option value="myComponent">Categories</option>
				</select>
				{selectedOption === 'myComponent' && <BlogsList listdData={category} />}
				</div>}
					{window.innerWidth > 640 &&<BlogsList listdData={category} />}
				</div>
				<div className="sm:w-[80%] mt-0 px-4">
					<MainProducts product={products} />
				</div>
			</div>
		</div>
	);
};

export default BlogNew;
